mapper.select:
SELECT t.*
FROM upload_tasks t
WHERE t.is_deleted = 0

    AND t.uploaded_by = #{userId}


    AND t.directory_id = #{query.directoryId}


    AND t.status = #{query.status}


    AND t.file_name LIKE CONCAT('%', #{query.fileName}, '%')


    AND t.create_time >= #{query.startTime}


    AND t.create_time <= #{query.endTime}

ORDER BY t.create_time DESC
